        import org.apache.log4j.Logger;
        import sailpoint.object.Identity;
        import sailpoint.api.ObjectUtil;
        import java.util.Iterator;
        import java.util.List;
        import sailpoint.api.Provisioner;
        import sailpoint.object.Identity;
        import sailpoint.object.Link;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningProject;        

        Logger logger = Logger.getLogger("com.CustomLogs");
        logger.debug("Enable Accounts step-START");

        boolean userStatus = false;
        String rehireType=null;
        Identity identityObject =  null;
        String applicationName = null;
        String applicationType = null;
        String accountName = null;
        ProvisioningPlan enablePlan = null;
        AccountRequest enableAcctReq =null;     

        Iterator linksIterator =null; 
        
        identity = ObjectUtil.lockIdentityByName(context,identityName);
		logger.debug("inside Process Conversion Step:::"+identityName);
        if(identity!= null){

        userStatus = getIdentityStatus(identityName);
        String status=(userStatus)? "active": "Inactive";

        try{

        List identityAccount = identity.getLinks();
        String strAction=identity.getAttribute("action");
        if(null!=identityAccount){

        linksIterator = identityAccount.iterator();
        while(linksIterator.hasNext()){
        Link accounts = (Link) linksIterator.next();
        applicationName = accounts.getApplicationName();
        applicationType = accounts.getApplication().getType();
        accountName = accounts.getNativeIdentity();        

        if(accounts.isDisabled() && null!=applicationName && null!=applicationType){  
        if(applicationType.equalsIgnoreCase("Active Directory - Direct") ){
        
        enableAcctReq = new AccountRequest();
        enablePlan = new ProvisioningPlan();
        enableAcctReq.setApplication(applicationName);
        enableAcctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
        enableAcctReq.setNativeIdentity(accountName);
        enablePlan.setIdentity(identity);
        enablePlan.add(enableAcctReq);        
        Provisioner prov=new Provisioner(context);
        prov.setNoLocking(true);
        prov.setOptimisticProvisioning(true);
        ProvisioningProject project = prov.compile(enablePlan);
        prov.execute(enablePlan);

        }

        }
        }
        }

        }catch(Exception e){

        logger.error("setEnableAccountRequest::Exception= "+e.printStackTrace());
        throw e;
        }
        logger.debug("Enable Accounts - STOP");

        }

//Write Audit records to IIQ.
String auditString1 = "Identity that was processed-Type Change: "+identityName;
String auditString2 = "conversion Process: "+rehireType;
String auditString3 = "Triggering the Rehire/Conversion Workflow on the identity : "+identityName;
writeAuditRecordToIIQ("PersonaMover" ,auditString1, auditString2,auditString3,identityName,"Persona Rehire");
